// Float and Color outputs are represented as 1x1 PixelBuffers
// containing the value, which is read by downstream Float/Color inputs.
var size = context.TileSize;
var buffer = new PixelBuffer(size, size);
var color = GetColor(parameters, "colorValue", Colors.White);
var floatVal = GetFloat(parameters, "floatValue", 0.5f);

// Encode the float value into all pixels (downstream Float ports read from pixel data)
buffer.ParallelForEachPixel((x, y) =>
{
    buffer.SetPixel(x, y, floatVal, floatVal, floatVal, 1f);
});

return buffer;
